class Solution:
    def maximumOr(self, nums: List[int], k: int) -> int:
        def check(x):
            cnt = 0
            for num in nums:
                t = x | num
                while t > num:
                    num <<= 1
                    cnt += 1
                    if cnt > k:
                        return False
            return cnt <= k

        l, r = 0, 2**31 - 1
        while l < r:
            mid = (l + r + 1) // 2
            if check(mid):
                l = mid
            else:
                r = mid - 1
        return l
```
